// src/pages/supervisor/index.jsx  –  All supervisor pages
import { useState, useEffect, useCallback } from "react";
import { taskAPI, userAPI, reportAPI, projectAPI } from "../../utils/api";
import { StatusBadge, Avatar, Toast } from "../../components/shared/index.jsx";
import TaskModal from "../../components/shared/TaskModal.jsx";
import { computeStats, formatMinutes, statusSelectClass } from "../../utils/helpers";
import { useAuth } from "../../hooks/useAuth";

// ── SUPERVISOR DASHBOARD ──────────────────────────────────────────────────────
export function SupervisorDashboard() {
  const [report,  setReport]  = useState([]);
  const [tasks,   setTasks]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(()=>{
    Promise.all([reportAPI.interns(), taskAPI.getAll()])
      .then(([r,t])=>{ setReport(r.report||[]); setTasks(t.tasks||[]); setLoading(false); })
      .catch(()=>setLoading(false));
  },[]);

  const { total, done, inProgress, hold } = computeStats(tasks);
  const totalMins = tasks.reduce((s,t)=>s+(parseInt(t.totalMinutes)||0),0);

  if (loading) return <div style={{padding:60,textAlign:"center"}}><div className="spinner"/></div>;

  return (
    <div className="animate-fadeUp">
      <div className="grid-4 mb-24">
        {[[" 👥","Active Interns",report.length,"stat-green","up"],["📋","Total Tasks",total,"stat-blue","neutral"],["✅","Completed",done,"stat-gold","up"],["⏸","On Hold",hold,"stat-red","warn"]].map(([icon,label,val,cls,chg])=>(
          <div key={label} className={`stat-card ${cls}`}><div className="stat-icon">{icon}</div><div className="stat-value">{val}</div><div className="stat-label">{label}</div><div className={`stat-change ${chg}`}>{chg==="up"?`↑ ${total?Math.round(done/total*100):0}% rate`:chg==="warn"?"Review needed":"All time"}</div></div>
        ))}
      </div>
      <div className="grid-2 mb-24">
        <div className="card">
          <div className="card-header"><div className="card-title">👥 Intern Performance</div></div>
          <div className="card-body">
            {report.map(intern=>(
              <div key={intern.id} style={{marginBottom:20}}>
                <div className="flex items-center gap-10 mb-8">
                  <Avatar initials={intern.avatar} color={intern.avatarColor} size="sm"/>
                  <div style={{flex:1}}>
                    <div style={{fontSize:13,fontWeight:600}}>{intern.name.split(" ")[0]}</div>
                    <div style={{fontSize:11,color:"var(--gray-400)"}}>{intern.position} · {intern.stats.total} tasks · {formatMinutes(intern.stats.totalMins)}</div>
                  </div>
                  <span style={{fontFamily:"Syne,sans-serif",fontWeight:700,fontSize:14,color:intern.stats.pct>70?"var(--green-500)":"var(--orange)"}}>{intern.stats.pct}%</span>
                </div>
                <div className="progress-bar"><div className={`progress-fill${intern.stats.pct<50?" warn":""}`} style={{width:intern.stats.pct+"%"}}/></div>
              </div>
            ))}
          </div>
        </div>
        <div>
          <div className="week-summary mb-16">
            <h3>📊 System Overview</h3>
