// ── ALL TASKS PAGE ─────────────────────────────────────────────────────────────
export function AllTasksPage() {
  const { user }   = useAuth();
  const [tasks,    setTasks]    = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [saving,   setSaving]   = useState(false);
  const [showModal,setShowModal]= useState(false);
  const [editTask, setEditTask] = useState(null);
  const [toast,    setToast]    = useState(null);
  const [status,   setStatus]   = useState("All");
  const [internId, setInternId] = useState("All");
  const [interns,  setInterns]  = useState([]);
  const [search,   setSearch]   = useState("");

  useEffect(()=>{ userAPI.getAll("intern").then(d=>setInterns(d.users||[])).catch(()=>{}); },[]);

  const load = useCallback(()=>{
    setLoading(true);
    taskAPI.getAll({ status:status!=="All"?status:undefined, internId:internId!=="All"?internId:undefined, search:search||undefined })
      .then(d=>{ setTasks(d.tasks||[]); setLoading(false); }).catch(()=>setLoading(false));
  },[status,internId,search]);

  useEffect(()=>{ load(); },[load]);

  const handleSave = async (form) => {
    setSaving(true);
    try {
      if (editTask) { const d=await taskAPI.update(editTask.id,form); setTasks(ts=>ts.map(t=>t.id===editTask.id?d.task:t)); setToast({msg:"Task updated!",type:"success"}); }
      else { const d=await taskAPI.create(form); setTasks(ts=>[d.task,...ts]); setToast({msg:"Task assigned!",type:"success"}); }
      setShowModal(false); setEditTask(null);
    } catch(e){ setToast({msg:e.message,type:"error"}); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this task?")) return;
    try { await taskAPI.delete(id); setTasks(ts=>ts.filter(t=>t.id!==id)); setToast({msg:"Deleted.",type:"success"}); }
    catch(e){ setToast({msg:e.message,type:"error"}); }
  };

  const handleCheck = async (id) => {
    try { const d=await taskAPI.toggleCheck(id); setTasks(ts=>ts.map(t=>t.id===id?d.task:t)); }
    catch(e){ setToast({msg:e.message,type:"error"}); }
  };

  return (
    <div className="animate-fadeUp">
      {toast && <Toast message={toast.msg} type={toast.type} onClose={()=>setToast(null)}/>}
      {showModal && <TaskModal task={editTask} currentUser={user} onClose={()=>{setShowModal(false);setEditTask(null);}} onSave={handleSave} loading={saving}/>}
      <div className="card">
        <div className="card-header"><div className="card-title">📋 All Tasks</div><button className="btn btn-primary" onClick={()=>{setEditTask(null);setShowModal(true);}}>+ Assign Task</button></div>
        <div style={{padding:"14px 24px",borderBottom:"1px solid var(--gray-100)"}}>
          <div className="filters">
            <div className="search-wrap"><span className="search-icon">🔍</span><input className="search-input" placeholder="Search…" value={search} onChange={e=>setSearch(e.target.value)}/></div>
            <select className="filter-select" value={status} onChange={e=>setStatus(e.target.value)}><option value="All">All Status</option>{["To Do","In Progress","Done","Hold"].map(s=><option key={s}>{s}</option>)}</select>
            <select className="filter-select" value={internId} onChange={e=>setInternId(e.target.value)}><option value="All">All Interns</option>{interns.map(i=><option key={i.id} value={i.id}>{i.name.split(" ")[0]}</option>)}</select>
            <span className="text-sm text-gray" style={{marginLeft:"auto"}}>{tasks.length} records</span>
          </div>
        </div>
        <div className="table-wrap">
          {loading?<div style={{padding:40,textAlign:"center"}}><div className="spinner"/></div>:tasks.length===0?(
            <div className="empty-state"><div className="empty-icon">📭</div><h3>No tasks found</h3></div>
          ):(
            <table>
              <thead><tr><th>Date</th><th>Intern</th><th>Project</th><th>Task</th><th>Status</th><th>Estimate</th><th>Mins</th><th>Doc</th><th>Checked By</th><th>Actions</th></tr></thead>
              <tbody>{tasks.map(t=>(
                <tr key={t.id}>
                  <td className="text-sm text-gray">{t.date}</td>
                  <td>{t.intern&&<div className="flex items-center gap-8"><Avatar initials={t.intern.avatar} color={t.intern.avatarColor} size="sm"/><span className="text-sm">{t.intern.name.split(" ")[0]}</span></div>}</td>
                  <td><span className="tag">{t.project}</span></td>
                  <td className="text-sm" style={{maxWidth:220}}>{t.task}</td>
                  <td><StatusBadge status={t.status}/></td>
                  <td className="text-sm">{t.estimateTime}</td>
                  <td className="text-sm text-bold">{t.totalMinutes}</td>
                  <td>{t.workDoc?<a href={t.workDoc} target="_blank" rel="noreferrer" style={{color:"var(--green-600)",fontSize:17}}>🔗</a>:"–"}</td>
                  <td>
                    <button onClick={()=>handleCheck(t.id)} style={{background:(t.adminChecked||[]).includes(user.username)?"#dcfce7":"#f3f4f6",border:"none",borderRadius:6,padding:"4px 10px",fontSize:11,fontWeight:700,cursor:"pointer",color:(t.adminChecked||[]).includes(user.username)?"#166534":"#6b7280",fontFamily:"inherit",transition:"all .2s"}}>
                      {(t.adminChecked||[]).includes(user.username)?"✓ Checked":"Mark"}
                    </button>
                  </td>
                  <td><div className="flex gap-6"><button className="btn btn-secondary btn-sm btn-icon" onClick={()=>{setEditTask(t);setShowModal(true);}}>✏️</button><button className="btn btn-danger btn-sm btn-icon" onClick={()=>handleDelete(t.id)}>🗑</button></div></td>
                </tr>
              ))}</tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

